"use client";

import { useState } from "react";

export default function AddToCart({ item }: any) {
  const [added, setAdded] = useState(false);

  return (
    <div>
      <button
        onClick={() => setAdded(true)}
        style={{
          background: "green",
          color: "white",
          padding: "5px 10px",
          marginTop: "10px",
          cursor: "pointer",
        }}
      >
        {added ? "Added ✅" : "Add to Cart"}
      </button>
    </div>
  );
}